SELECT COUNT(*) AS movie_count
FROM movies
WHERE Distributor = 'Warner Bros.';

SELECT COUNT(*) AS film_count
FROM movies
WHERE "Rotten Tomatoes Rating" > 90;

SELECT 100.0 * SUM(CASE WHEN weather = 'sun' THEN 1 ELSE 0 END) / COUNT(*) AS pct_sunny_days
FROM seattle_weather
WHERE date_part('month', date) IN (6, 7, 8);

SELECT AVG(order_total) AS avg_total_payment_value_per_order
FROM (
  SELECT order_id, SUM(payment_value) AS order_total
  FROM olist_order_payments
  GROUP BY order_id
) AS per_order;

SELECT COUNT(*) AS order_count
FROM olist_orders
WHERE date_part('year', order_purchase_timestamp) = 2099;; SELECT COUNT(*) AS order_count FROM northwind_orders WHERE date_part('year', orderDate) = 2099;

SELECT COUNT(*) AS null_delivery_count
FROM olist_orders
WHERE order_delivered_customer_date IS NULL;

SELECT COUNT(*) AS order_count
FROM olist_orders
WHERE strftime(order_purchase_timestamp, '%Y-%m') = '2017-11';
